 10	export function openStore(
 11	  path: string,
 12	  options: { create?: boolean; readOnly?: boolean } = {},
 13	): DatabaseSync {
 14	  if (options.create) {
 15	    mkdirSync(dirname(path), { recursive: true });
 16	  }
 17	  const database = new DatabaseSync(path, {
 18	    open: true,
 19	    readOnly: options.readOnly ?? false,
 20	  });
 21	  database.exec("PRAGMA foreign_keys = ON; PRAGMA busy_timeout = 1000;");
 22	  if (options.create) {
 23	    chmodSync(path, 0o600);
 24	  }
 25	  return database;
 26	}
 27	
 28	export function migrateStore(path: string): void {
 29	  const database = openStore(path, { create: true });
 30	  try {
 31	    database.exec(readFileSync(MIGRATION_PATH, "utf8"));
 32	  } finally {
 33	    database.close();
 34	  }
 35	}
