 43	export function dropStoreSchema(path: string): void {
 44	  const database = openStore(path);
 45	  try {
 46	    database.exec(`
 47	      DROP TABLE IF EXISTS notes;
 48	      DROP TABLE IF EXISTS access_tokens;
 49	      DROP TABLE IF EXISTS users;
 50	      DROP TABLE IF EXISTS organizations;
 51	    `);
 52	  } finally {
 53	    database.close();
 54	  }
 55	}
