  5	type NoteRow = {
  6	  public_id: string;
  7	  title: string;
  8	  body: string;
  9	  owner_id: string;
 10	  organization_id: string;
 11	  created_at: string;
 12	  updated_at: string;
 13	};
 14	
 15	export type CreateNoteRecord = {
 16	  publicId: string;
 17	  title: string;
 18	  body: string;
 19	  createdAt: string;
 20	};
 21	
 22	export type NotePatch = {
 23	  title?: string;
 24	  body?: string;
 25	  updatedAt: string;
 26	};
 27	
 28	export class NoteRepository {
 29	  create(principal: Principal, record: CreateNoteRecord): Note {
 30	    const database = openStore(principal.storePath);
 31	    try {
 32	      database.prepare(
 33	        `INSERT INTO notes
 34	          (public_id, title, body, owner_id, organization_id, created_at, updated_at)
 35	         VALUES (?, ?, ?, ?, ?, ?, ?)`,
 36	      ).run(
 37	        record.publicId,
 38	        record.title,
 39	        record.body,
 40	        principal.userId,
 41	        principal.organizationId,
 42	        record.createdAt,
 43	        record.createdAt,
 44	      );
 45	      return this.findWithDatabase(database, principal, record.publicId) as Note;
 46	    } finally {
 47	      database.close();
 48	    }
 49	  }
 50	
 51	  find(principal: Principal, publicId: string): Note | undefined {
 52	    const database = openStore(principal.storePath, { readOnly: true });
 53	    try {
 54	      return this.findWithDatabase(database, principal, publicId);
 55	    } finally {
 56	      database.close();
 57	    }
 58	  }
 59	
 60	  list(
 61	    principal: Principal,
 62	    limit: number,
 63	    cursor?: Cursor,
 64	  ): { notes: Note[]; hasMore: boolean } {
 65	    const database = openStore(principal.storePath, { readOnly: true });
 66	    try {
 67	      const rows = cursor
 68	        ? database.prepare(
 69	          `${SELECT_FIELDS} WHERE organization_id = ?
 70	           AND (created_at < ? OR (created_at = ? AND public_id < ?))
 71	           ORDER BY created_at DESC, public_id DESC LIMIT ?`,
 72	        ).all(
 73	          principal.organizationId,
 74	          cursor.createdAt,
 75	          cursor.createdAt,
 76	          cursor.publicId,
 77	          limit + 1,
 78	        )
 79	        : database.prepare(
 80	          `${SELECT_FIELDS} WHERE organization_id = ?
 81	           ORDER BY created_at DESC, public_id DESC LIMIT ?`,
 82	        ).all(principal.organizationId, limit + 1);
 83	      return {
 84	        notes: (rows as NoteRow[]).slice(0, limit).map(toNote),
 85	        hasMore: rows.length > limit,
 86	      };
 87	    } finally {
 88	      database.close();
 89	    }
 90	  }
 91	
 92	  update(principal: Principal, publicId: string, patch: NotePatch): Note | undefined {
 93	    const database = openStore(principal.storePath);
 94	    try {
 95	      const result = database.prepare(
 96	        `UPDATE notes SET
 97	          title = COALESCE(?, title),
 98	          body = COALESCE(?, body),
 99	          updated_at = ?
100	         WHERE public_id = ? AND organization_id = ?`,
101	      ).run(
102	        patch.title ?? null,
103	        patch.body ?? null,
104	        patch.updatedAt,
105	        publicId,
106	        principal.organizationId,
107	      );
108	      if (result.changes === 0) return undefined;
109	      return this.findWithDatabase(database, principal, publicId);
110	    } finally {
111	      database.close();
112	    }
113	  }
114	
115	  delete(principal: Principal, publicId: string): boolean {
116	    const database = openStore(principal.storePath);
117	    try {
118	      const result = database.prepare(
119	        "DELETE FROM notes WHERE public_id = ? AND organization_id = ?",
120	      ).run(publicId, principal.organizationId);
121	      return result.changes === 1;
122	    } finally {
123	      database.close();
124	    }
125	  }
126	
127	  private findWithDatabase(
128	    database: ReturnType<typeof openStore>,
129	    principal: Principal,
130	    publicId: string,
131	  ): Note | undefined {
132	    const row = database.prepare(
133	      `${SELECT_FIELDS} WHERE public_id = ? AND organization_id = ?`,
134	    ).get(publicId, principal.organizationId) as NoteRow | undefined;
135	    return row ? toNote(row) : undefined;
136	  }
137	}
