139	const SELECT_FIELDS = `SELECT public_id, title, body, owner_id,
140	  organization_id, created_at, updated_at FROM notes`;
141	
142	function toNote(row: NoteRow): Note {
143	  return {
144	    id: row.public_id,
145	    title: row.title,
146	    body: row.body,
147	    ownerId: row.owner_id,
148	    organizationId: row.organization_id,
149	    createdAt: row.created_at,
150	    updatedAt: row.updated_at,
151	  };
152	}
