  8	import type { Logger, Principal } from "./types.ts";
  9	
 10	type FailureWindow = {
 11	  startedAt: number;
 12	  count: number;
 13	  didLogSpike: boolean;
 14	};
 15	
 16	type TokenRow = {
 17	  token_hash: Uint8Array;
 18	  user_id: string;
 19	  organization_id: string;
 20	  expires_at: string;
 21	};
 22	
 23	export class Authenticator {
 24	  readonly #failures = new Map<string, FailureWindow>();
 25	  readonly config: AppConfig;
 26	  readonly logger: Logger;
 27	  readonly now: () => Date;
 28	
 29	  constructor(
 30	    config: AppConfig,
 31	    logger: Logger,
 32	    now: () => Date = () => new Date(),
 33	  ) {
 34	    this.config = config;
 35	    this.logger = logger;
 36	    this.now = now;
 37	    this.validateStores();
 38	  }
 39	
 40	  authenticate(header: string | undefined, ip: string): Principal {
 41	    if (this.isThrottled(ip)) {
 42	      throw new AppError(429, "AUTH_RATE_LIMITED", "Try again in one minute.");
 43	    }
 44	    const token = parseBearer(header);
 45	    if (!token) return this.reject(ip);
 46	    const matches = this.findMatches(hashToken(token));
 47	    if (matches.length !== 1) return this.reject(ip);
 48	    const match = matches[0];
 49	    if (!match || new Date(match.row.expires_at) <= this.now()) {
 50	      return this.reject(ip);
 51	    }
 52	    this.#failures.delete(ip);
 53	    return {
 54	      userId: match.row.user_id,
 55	      organizationId: match.row.organization_id,
 56	      storePath: match.storePath,
 57	    };
 58	  }
 59	
 60	  validateStores(): void {
 61	    const seenHashes = new Set<string>();
 62	    let organizationCount = 0;
 63	    for (const storePath of getStorePaths(this.config)) {
 64	      const database = openStore(storePath, { readOnly: true });
 65	      try {
 66	        const rows = database.prepare(
 67	          `SELECT a.token_hash, u.organization_id
 68	           FROM access_tokens a JOIN users u ON u.public_id = a.user_id`,
 69	        ).all() as { token_hash: Uint8Array; organization_id: string }[];
 70	        const organizations = database.prepare(
 71	          "SELECT COUNT(*) AS count FROM organizations",
 72	        ).get() as { count: number };
 73	        if (organizations.count !== 1) {
 74	          throw new Error("Each store must contain exactly one organization");
 75	        }
 76	        organizationCount += organizations.count;
 77	        for (const row of rows) {
 78	          const key = Buffer.from(row.token_hash).toString("hex");
 79	          if (seenHashes.has(key)) throw new Error("Duplicate token hash across stores");
 80	          seenHashes.add(key);
 81	        }
 82	      } finally {
 83	        database.close();
 84	      }
 85	    }
 86	    if (organizationCount !== 2) throw new Error("Exactly two stores are required");
 87	  }
 88	
 89	  private findMatches(digest: Buffer) {
 90	    const matches: { row: TokenRow; storePath: string }[] = [];
 91	    for (const organization of this.config.identities.organizations) {
 92	      const storePath = join(this.config.dataDir, organization.store);
 93	      const database = openStore(storePath, { readOnly: true });
 94	      try {
 95	        const rows = database.prepare(
 96	          `SELECT a.token_hash, a.user_id, a.expires_at, u.organization_id
 97	           FROM access_tokens a JOIN users u ON u.public_id = a.user_id`,
 98	        ).all() as TokenRow[];
 99	        for (const row of rows) {
100	          const stored = Buffer.from(row.token_hash);
101	          if (stored.length === digest.length && timingSafeEqual(stored, digest)) {
102	            matches.push({ row, storePath });
103	          }
104	        }
105	      } finally {
106	        database.close();
107	      }
108	    }
109	    return matches;
110	  }
111	
112	  private reject(ip: string): never {
113	    const current = this.recordFailure(ip);
114	    if (current.count > 30) {
115	      throw new AppError(429, "AUTH_RATE_LIMITED", "Try again in one minute.");
116	    }
117	    throw new AppError(
118	      401,
119	      "AUTHENTICATION_REQUIRED",
120	      "Provide a valid, unexpired bearer token.",
121	    );
122	  }
123	
124	  private isThrottled(ip: string): boolean {
125	    return (this.getActiveFailure(ip)?.count ?? 0) > 30;
126	  }
127	
128	  private recordFailure(ip: string): FailureWindow {
129	    this.pruneFailures();
130	    const failure = this.getActiveFailure(ip) ?? {
131	      startedAt: this.now().getTime(),
132	      count: 0,
133	      didLogSpike: false,
134	    };
135	    failure.count += 1;
136	    if (failure.count >= 10 && !failure.didLogSpike) {
137	      failure.didLogSpike = true;
138	      this.logger.write({ event: "auth_denial_spike", ip, outcome: "denied" });
139	    }
140	    this.#failures.set(ip, failure);
141	    return failure;
142	  }
143	
144	  private getActiveFailure(ip: string): FailureWindow | undefined {
145	    const failure = this.#failures.get(ip);
146	    if (failure && this.now().getTime() - failure.startedAt < 60_000) {
147	      return failure;
148	    }
149	    if (failure) this.#failures.delete(ip);
150	    return undefined;
151	  }
152	
153	  private pruneFailures(): void {
154	    for (const ip of this.#failures.keys()) this.getActiveFailure(ip);
155	    while (this.#failures.size >= 1_000) {
156	      const oldest = this.#failures.keys().next().value as string | undefined;
157	      if (!oldest) break;
158	      this.#failures.delete(oldest);
159	    }
160	  }
161	}
162	
163	function parseBearer(header: string | undefined): string | undefined {
164	  if (!header) return undefined;
165	  const match = /^Bearer ([^\s]+)$/.exec(header);
166	  return match?.[1];
167	}
