  8	export type SeedOptions = {
  9	  config: AppConfig;
 10	  tokens: Record<string, string | undefined>;
 11	  now?: Date;
 12	};
 13	
 14	export function seedStores(options: SeedOptions): void {
 15	  const entries = collectTokens(options);
 16	  assertDistinctTokens(entries.map((item) => item.token));
 17	  const expiresAt = new Date(
 18	    (options.now ?? new Date()).getTime() + 8 * 60 * 60 * 1000,
 19	  ).toISOString();
 20	  for (const organization of options.config.identities.organizations) {
 21	    const storePath = join(options.config.dataDir, organization.store);
 22	    migrateStore(storePath);
 23	    seedOrganization(storePath, organization, entries, expiresAt);
 24	  }
 25	}
 26	
 27	function collectTokens(options: SeedOptions) {
 28	  return options.config.identities.organizations.flatMap((organization) =>
 29	    organization.users.map((user) => {
 30	      const token = options.tokens[user.tokenEnv];
 31	      if (!token || Buffer.byteLength(token) < 32) {
 32	        throw new Error(`${user.tokenEnv} must contain at least 32 bytes`);
 33	      }
 34	      return { userId: user.publicId, token };
 35	    })
 36	  );
 37	}
 38	
 39	function assertDistinctTokens(tokens: string[]): void {
 40	  const hashes = tokens.map(hashToken);
 41	  if (new Set(hashes.map((hash) => hash.toString("hex"))).size !== hashes.length) {
 42	    throw new Error("Bearer tokens must be distinct");
 43	  }
 44	}
 45	
 46	function seedOrganization(
 47	  storePath: string,
 48	  organization: IdentityOrganization,
 49	  entries: { userId: string; token: string }[],
 50	  expiresAt: string,
 51	): void {
 52	  const database = openStore(storePath);
 53	  try {
 54	    database.exec("BEGIN IMMEDIATE");
 55	    database.prepare(
 56	      "INSERT OR REPLACE INTO organizations(public_id, name) VALUES (?, ?)",
 57	    ).run(organization.publicId, organization.name);
 58	    for (const user of organization.users) {
 59	      database.prepare(
 60	        "INSERT OR REPLACE INTO users(public_id, organization_id, name) VALUES (?, ?, ?)",
 61	      ).run(user.publicId, organization.publicId, user.name);
 62	      const token = entries.find((item) => item.userId === user.publicId);
 63	      if (!token) throw new Error("Seed token was not collected");
 64	      database.prepare("DELETE FROM access_tokens WHERE user_id = ?").run(user.publicId);
 65	      database.prepare(
 66	        "INSERT INTO access_tokens(token_hash, user_id, expires_at) VALUES (?, ?, ?)",
 67	      ).run(hashToken(token.token), user.publicId, expiresAt);
 68	    }
 69	    database.exec("COMMIT");
 70	  } catch (error) {
 71	    database.exec("ROLLBACK");
 72	    throw error;
 73	  } finally {
 74	    database.close();
 75	  }
 76	}
 77	
 78	export function hashToken(token: string): Buffer {
 79	  return createHash("sha256").update(token).digest();
 80	}
 81	
 82	if (process.argv[1] === fileURLToPath(import.meta.url)) {
 83	  seedStores({ config: loadAppConfig(), tokens: process.env });
 84	  process.stdout.write("Seeded two organization stores.\n");
 85	}

  1	# Local runbook
  2	
  3	## Start and stop
  4	
  5	Follow the README Quick Start with an explicit `DATA_DIR`. Stop with `SIGINT` or
  6	`SIGTERM`; the process closes its listener. SQLite connections are request
  7	scoped and closed in `finally`.
  8	
  9	## Store unavailable
 10	
 11	Signal: `/healthz` returns 503 with code `STORE_UNAVAILABLE`, or startup reports
 12	a missing or invalid configured store.
 13	
 14	1. Stop the process.
 15	2. Confirm both `organization-a.sqlite` and `organization-b.sqlite` exist under
 16	   `DATA_DIR`, are readable by the current user, and have mode `0600`.
 17	3. Do not create an empty replacement for a store containing notes. Restore the
 18	   known local test copy if one exists.
 19	4. If this is a disposable evaluation, rerun `npm run seed`.
 20	5. Restart and require `/healthz` to return 200 before continuing.
 21	
 22	## Authentication denial spike
 23	
 24	Ten failed authentications from an IP in one minute emit
 25	`auth_denial_spike`. More than 30 failures in that window return 429.
 26	
 27	Confirm that the caller uses one of the most recently seeded token values and
 28	that token age is under eight hours. Logs deliberately contain neither bearer
 29	tokens nor note title/body content. Rotate tokens by the README procedure if
 30	exposure is suspected.
 31	
 32	## Recovery and rollback
 33	
 34	There is no backup promise. For evaluator data, stop the process and restore
 35	both store files from the same known test copy. Never copy a live SQLite file.
 36	Run `npm run verify` after restoration. Notes use hard delete and cannot be
 37	recovered through the API.
  1	# ADR 001: Local tenant isolation
  2	
  3	Status: accepted
  4	
  5	## Context
  6	
  7	The evaluator must prove that a user in one of two fixed organizations cannot
  8	observe or mutate a note in the other organization, even with its real public
  9	id. Runtime and tests must remain local and restart-safe, with no database
 10	service.
 11	
 12	## Decision
 13	
 14	Use one SQLite file per organization. Authentication hashes the supplied bearer
 15	token, searches token rows in the fixed two-store registry, and binds one
 16	immutable principal and store path. Notes operations open only that selected
 17	file and also predicate every query and mutation on the principal's organization
 18	id. Composite foreign keys prevent a note owner from belonging to another
 19	organization.
 20	
 21	Flip point: a third organization is required, store-open time exceeds 100 ms
 22	p95, a second process writes the files, or demand exceeds 10 requests per
 23	second.
 24	
 25	Blast radius: changing this decision replaces authentication lookup, the store
 26	registry, every repository constructor, migrations, seed layout, and tenant
 27	isolation tests.
 28	
 29	## Consequences
 30	
 31	Physical separation makes a missed shared-table filter insufficient to expose
 32	the other organization's data. The fixed store registry is intentionally not a
 33	general provisioning system. Authentication performs two small local token
 34	reads; note operations retain no cross-store connection.
 35	
 36	## Rejected alternatives
 37	
 38	- One shared embedded database was rejected because SQLite cannot enforce
 39	  application row-level security if a predicate is missed.
 40	- PostgreSQL with forced row-level security was rejected because it adds a
 41	  network service and violates the offline local execution constraint.
  1	import { readFileSync } from "node:fs";
  2	import { dirname, join, resolve } from "node:path";
  3	import { fileURLToPath } from "node:url";
  4	
  5	export type IdentityUser = {
  6	  publicId: string;
  7	  name: string;
  8	  tokenEnv: string;
  9	};
 10	
 11	export type IdentityOrganization = {
 12	  publicId: string;
 13	  name: string;
 14	  store: string;
 15	  users: IdentityUser[];
 16	};
 17	
 18	export type IdentityConfig = {
 19	  organizations: IdentityOrganization[];
 20	};
 21	
 22	export type AppConfig = {
 23	  dataDir: string;
 24	  identities: IdentityConfig;
 25	};
 26	
 27	const MODULE_DIR = dirname(fileURLToPath(import.meta.url));
 28	const DEFAULT_IDENTITIES_PATH = resolve(MODULE_DIR, "../config/identities.json");
 29	
 30	export function loadIdentityConfig(path = DEFAULT_IDENTITIES_PATH): IdentityConfig {
 31	  const parsed: unknown = JSON.parse(readFileSync(path, "utf8"));
 32	  if (!isIdentityConfig(parsed)) {
 33	    throw new Error("Identity configuration is invalid");
 34	  }
 35	  return parsed;
 36	}
 37	
 38	export function loadAppConfig(
 39	  dataDir = process.env.DATA_DIR ?? resolve("data"),
 40	): AppConfig {
 41	  return { dataDir: resolve(dataDir), identities: loadIdentityConfig() };
 42	}
 43	
 44	export function getStorePaths(config: AppConfig): string[] {
 45	  return config.identities.organizations.map((item) =>
 46	    join(config.dataDir, item.store),
 47	  );
 48	}
 49	
 50	function isIdentityConfig(value: unknown): value is IdentityConfig {
 51	  if (!isRecord(value) || !Array.isArray(value.organizations)) {
 52	    return false;
 53	  }
 54	  return value.organizations.length === 2 &&
 55	    value.organizations.every(isOrganization);
 56	}
 57	
 58	function isOrganization(value: unknown): value is IdentityOrganization {
 59	  return isRecord(value) &&
 60	    typeof value.publicId === "string" &&
 61	    typeof value.name === "string" &&
 62	    typeof value.store === "string" &&
 63	    Array.isArray(value.users) &&
 64	    value.users.length === 2 &&
 65	    value.users.every(isUser);
 66	}
 67	
 68	function isUser(value: unknown): value is IdentityUser {
 69	  return isRecord(value) &&
 70	    typeof value.publicId === "string" &&
 71	    typeof value.name === "string" &&
 72	    typeof value.tokenEnv === "string";
 73	}
 74	
 75	function isRecord(value: unknown): value is Record<string, unknown> {
 76	  return typeof value === "object" && value !== null;
 77	}
