 38	export function createApp(options: AppOptions = {}) {
 39	  const config = options.config ?? loadAppConfig();
 40	  const clock = options.clock ?? { now: () => new Date() };
 41	  const ids = options.ids ?? { next: () => randomUUID() };
 42	  const logger = options.logger ?? createLogger();
 43	  const auth = new Authenticator(config, logger, () => clock.now());
 44	  const notes = new NotesService(new NoteRepository(), clock, ids);
 45	  let server: Server | undefined;
