 47	  async function inject(request: InjectOptions): Promise<InjectResponse> {
 48	    const requestId = randomUUID();
 49	    const url = new URL(request.url, "http://127.0.0.1");
 50	    const headers = normalizeHeaders(request.headers);
 51	    try {
 52	      enforceBodyLimit(request.payload);
 53	      const publicResponse = publicRoute(request.method.toUpperCase(), url, config);
 54	      if (publicResponse) return response(publicResponse.statusCode, publicResponse.body);
 55	      const principal = auth.authenticate(
 56	        headers.authorization,
 57	        request.remoteAddress ?? "127.0.0.1",
 58	      );
 59	      const result = executeNotesRoute(
 60	        notes,
 61	        {
 62	          method: request.method.toUpperCase(),
 63	          pathname: url.pathname,
 64	          query: url.searchParams,
 65	          payload: request.payload,
 66	        },
 67	        principal,
 68	      );
 69	      if (!result) throw new AppError(404, "ROUTE_NOT_FOUND", "The route does not exist.");
 70	      logger.write({
 71	        requestId,
 72	        actor: principal.userId,
 73	        organization: principal.organizationId,
 74	        action: result.action,
 75	        target: result.target,
 76	        outcome: "success",
 77	      });
 78	      return response(result.statusCode, result.body);
 79	    } catch (error) {
 80	      const problem = toProblem(error, url.pathname);
 81	      logger.write({ requestId, event: "request_denied", code: problem.code, outcome: "denied" });
 82	      return response(problem.status, problem, "application/problem+json");
 83	    }
 84	  }
 85	
 86	  async function listen(port = 3000, host = "127.0.0.1"): Promise<string> {
 87	    if (server) throw new Error("Application is already listening");
 88	    server = createServer(async (request, nativeResponse) => {
 89	      let result: InjectResponse;
 90	      try {
 91	        const payload = await readBody(request);
 92	        result = await inject({
 93	          method: request.method ?? "GET",
 94	          url: request.url ?? "/",
 95	          headers: Object.fromEntries(
 96	            Object.entries(request.headers).flatMap(([key, value]) =>
 97	              typeof value === "string" ? [[key, value]] : []),
 98	          ),
 99	          ...(payload === undefined ? {} : { payload }),
100	          remoteAddress: request.socket.remoteAddress ?? "unknown",
101	        });
102	      } catch (error) {
103	        const problem = toProblem(error, request.url ?? "/");
104	        result = response(problem.status, problem, "application/problem+json");
105	      }
106	      nativeResponse.writeHead(result.statusCode, result.headers);
107	      nativeResponse.end(result.body);
108	    });
109	    await new Promise<void>((resolve) => server?.listen(port, host, resolve));
110	    const address = server.address();
111	    const actualPort = typeof address === "object" && address ? address.port : port;
112	    return `http://${host}:${actualPort}`;
113	  }
114	
115	  async function close(): Promise<void> {
116	    if (!server) return;
117	    const current = server;
118	    server = undefined;
119	    await new Promise<void>((resolve, reject) =>
120	      current.close((error) => error ? reject(error) : resolve())
121	    );
122	  }
123	
124	  return { inject, listen, close };
125	}
