127	function publicRoute(method: string, url: URL, config: AppConfig) {
128	  if (method === "GET" && url.pathname === "/openapi.json") {
129	    return { statusCode: 200, body: openApiDocument };
130	  }
131	  if (method === "GET" && url.pathname === "/healthz") {
132	    if (checkHealth(config)) {
133	      return { statusCode: 200, body: { status: "ok", stores: 2 } };
134	    }
135	    throw new AppError(503, "STORE_UNAVAILABLE", "A configured store is unavailable.");
136	  }
137	  return undefined;
138	}
139	
140	function response(
141	  statusCode: number,
142	  body?: unknown,
143	  contentType = "application/json",
144	): InjectResponse {
145	  const text = body === undefined ? "" : JSON.stringify(body);
146	  return {
147	    statusCode,
148	    headers: {
149	      ...SECURITY_HEADERS,
150	      "content-type": contentType,
151	    },
152	    body: text,
153	    json: () => JSON.parse(text),
154	  };
155	}
156	
157	function normalizeHeaders(headers?: Record<string, string>): Record<string, string> {
158	  return Object.fromEntries(
159	    Object.entries(headers ?? {}).map(([key, value]) => [key.toLowerCase(), value]),
160	  );
161	}
162	
163	function enforceBodyLimit(payload: unknown): void {
164	  if (payload !== undefined && Buffer.byteLength(JSON.stringify(payload)) > 16 * 1024) {
165	    throw new AppError(413, "PAYLOAD_TOO_LARGE", "Request bodies are limited to 16 KiB.");
166	  }
167	}
168	
169	async function readBody(request: import("node:http").IncomingMessage): Promise<unknown> {
170	  const chunks: Buffer[] = [];
171	  let length = 0;
172	  let isTooLarge = false;
173	  for await (const chunk of request) {
174	    const buffer = Buffer.from(chunk);
175	    length += buffer.length;
176	    if (length > 16 * 1024) isTooLarge = true;
177	    if (!isTooLarge) chunks.push(buffer);
178	  }
179	  if (isTooLarge) {
180	    throw new AppError(413, "PAYLOAD_TOO_LARGE", "Request bodies are limited to 16 KiB.");
181	  }
182	  if (chunks.length === 0) return undefined;
183	  try {
184	    return JSON.parse(Buffer.concat(chunks).toString());
185	  } catch {
186	    throw new AppError(400, "INVALID_JSON", "The request body must be valid JSON.");
187	  }
188	}
