  3	export function createLogger(
  4	  sink: (line: string) => void = (line) => process.stdout.write(`${line}\n`),
  5	): Logger {
  6	  return {
  7	    write(event): void {
  8	      sink(JSON.stringify({ time: new Date().toISOString(), ...sanitize(event) }));
  9	    },
 10	  };
 11	}
 12	
 13	function sanitize(event: Record<string, unknown>): Record<string, unknown> {
 14	  const blocked = new Set(["authorization", "token", "title", "body"]);
 15	  return Object.fromEntries(
 16	    Object.entries(event)
 17	      .filter(([key]) => !blocked.has(key.toLowerCase()))
 18	      .map(([key, value]) => [key, sanitizeValue(value)]),
 19	  );
 20	}
 21	
 22	function sanitizeValue(value: unknown): unknown {
 23	  if (typeof value === "string" && /^Bearer /i.test(value)) return "[REDACTED]";
 24	  return value;
 25	}
